                    {filteredGigs.filter(g => g.status === 'live').map(gig => {
                      const gigDateTime = gig.gigDate && gig.gigTime 
                        ? `${new Date(gig.gigDate).toLocaleDateString('en-US', {month: 'short', day: 'numeric'})} at ${gig.gigTime}`
                        : 'Time TBD';
                      
