                  .map((song) => {
                    const voteCount = liveGigData.votes[Math.floor(song.id)] || 0;
                    return (
                      <div key={song.id} className="bg-gray-500/20 border border-gray-600 p-4 rounded-lg mb-2 opacity-60">
